import React, { Component } from 'react';
import { useMediaQuery } from 'react-responsive'
import Iframe from 'react-iframe'
import ucsfLogo from './images/ucsfHealth.webp'
import { Fade } from 'react-slideshow-image'
import pnImage from './images/parnassus.jpeg'
import mzImage from './images/mz.jpg'
import mbImage from './images/mb.jpg'
import vaImage from './images/va.jpg'
import 'react-slideshow-image/dist/styles.css'
import { slide as HMenu } from 'react-burger-menu'


var styles = {
  bmBurgerButton: {
    position: 'relative',
    width: '36px',
    height: '30px',
    left: '10px',
    top: '5px'
  },
  bmBurgerBars: {
    background: '#052049'
  },
  bmBurgerBarsHover: {
    background: '#052049'
  },
  bmCrossButton: {
    height: '24px',
    width: '24px'
  },
  bmCross: {
    background: '#052049'
  },
  bmMenuWrap: {
    position: 'fixed',
    height: '100%',
    top: '0px'
  },
  bmMenu: {
    background: '#E2F4FC'
  },
  bmMorphShape: {
    fill: '#052049'
  },
  bmItemList: {
    color: '#052049',
    padding: '0.8em'
  },
  bmItem: {
    display: 'inline-block'
  },
  bmOverlay: {
    background: 'rgba(0, 0, 0, 0.3)'
  }
}



const spanStyle = {
    padding: '20px',
    //background: '#efefef',
    color: '#000000'
  }

  const divStyle = {
    display: 'flex',
    alignItems: 'center',
    justifyContent: 'center',
    backgroundSize: 'cover',
    height: "100%"
  }
  const fadeImages = [
    {
      url: pnImage,
      caption: ''
    },
    {
      url: mbImage,
      caption: ''
    },
    {
      url: mzImage,
      caption: ''
    }
  ];



const Desktop = ({ children }) => {
    const isDesktop = useMediaQuery({ minWidth: 992 })
    return isDesktop ? children : null
  }
  const Tablet = ({ children }) => {
    const isTablet = useMediaQuery({ minWidth: 768, maxWidth: 991 })
    return isTablet ? children : null
  }
  const Mobile = ({ children }) => {
    const isMobile = useMediaQuery({ maxWidth: 767 })
    return isMobile ? children : null
  }
  const Default = ({ children }) => {
    const isNotMobile = useMediaQuery({ minWidth: 768 })
    return isNotMobile ? children : null
  }
  /*
